import React, { useState, useEffect } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import Layout from '../components/4_unity/Layout';
import Header from '../components/3_organism/Header';
import FooterSection from '../components/3_organism/FooterSection';
import SectionTitle from '../components/1_atoms/SectionTitle';
import { useAuth } from '../hooks/useAuth';
import apiClient from '../api/apiClient';

const statsIcons = {
  age: '/icons/health.svg',
  money: '/icons/money.svg',
  health: '/icons/health.svg',
  happiness: '/icons/mood.svg',
  annualSavings: '/icons/income.svg',
  income: '/icons/income.svg',
};

function GamePage() {
  const { sessionGameID } = useParams();
  const navigate = useNavigate();
  const { isAuthenticated, logout } = useAuth();
  const [background, setBackground] = useState(null);
  const [roundData, setRoundData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [roundLoading, setRoundLoading] = useState(false);
  const [error, setError] = useState(null);
  const [difficulty, setDifficulty] = useState('MEDIUM');

  useEffect(() => {
    if (!isAuthenticated) {
      navigate('/login');
    }
  }, [isAuthenticated, navigate]);

  useEffect(() => {
    const loadGame = async () => {
      setError(null);
      setLoading(true);

      try {
        const backgroundResponse = await apiClient.get(`/v1/background/${difficulty}/${sessionGameID}`);
        setBackground(backgroundResponse);
      } catch (err) {
        setError(err.message || 'Не удалось загрузить предысторию.');
      } finally {
        setLoading(false);
      }
    };

    if (sessionGameID) {
      loadGame();
    }
  }, [difficulty, sessionGameID]);

  const loadRound = async () => {
    if (!sessionGameID) {
      return;
    }

    setError(null);
    setRoundLoading(true);

    try {
      const response = await apiClient.get(`/v1/round/${sessionGameID}`);
      setRoundData(response);
    } catch (err) {
      setError(err.message || 'Не удалось загрузить ход.');
    } finally {
      setRoundLoading(false);
    }
  };

  useEffect(() => {
    if (sessionGameID) {
      loadRound();
    }
  }, [sessionGameID]);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const getStatRows = () => {
    if (!background?.status) {
      return [];
    }

    return Object.entries(background.status).map(([key, value]) => ({
      key,
      label: key === 'age' ? 'Возраст' : key === 'money' ? 'Деньги' : key === 'health' ? 'Здоровье' : key === 'happiness' ? 'Счастье' : key === 'annualSavings' ? 'Сбережения' : key,
      value,
      icon: statsIcons[key] || '/icons/health.svg',
    }));
  };

  return (
    <Layout>
      <Header />
      <main className="game-page">
        <section className="game-hero">
          <div className="game-hero__top">
            <SectionTitle
              title="Игровая сессия"
              subtitle={`Сессия ${sessionGameID || ''}`}
            />
            <div className="game-hero__actions">
              <button className="button button--secondary" onClick={() => navigate('/account')}>
                Назад в аккаунт
              </button>
              <button className="button button--secondary" onClick={handleLogout}>
                Выйти
              </button>
            </div>
          </div>

          {error && <div className="auth-error">{error}</div>}

          <div className="game-content-grid">
            <div className="game-panel">
              <div className="game-panel__head">
                <h3>Предыстория</h3>
                <select value={difficulty} onChange={(event) => setDifficulty(event.target.value)}>
                  <option value="EASY">Лёгкая</option>
                  <option value="MEDIUM">Средняя</option>
                  <option value="HARD">Сложная</option>
                </select>
              </div>
              {loading ? (
                <div className="panel-loading">Загрузка предыстории...</div>
              ) : (
                <div className="game-panel__body">
                  <p>{background?.background || 'Предыстория пока отсутствует.'}</p>
                </div>
              )}
            </div>

            <div className="stat-grid">
              {getStatRows().map((stat) => (
                <div className="stat-card" key={stat.key}>
                  <img src={stat.icon} alt={stat.label} />
                  <div>
                    <span>{stat.label}</span>
                    <strong>{stat.value}</strong>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="round-panel">
            <div className="round-panel__head">
              <h3>Текущий ход</h3>
              <button className="button button--primary" type="button" onClick={loadRound} disabled={roundLoading}>
                {roundLoading ? 'Обновление...' : 'Следующий ход'}
              </button>
            </div>
            <div className="round-panel__body">
              {roundLoading ? (
                <p>Загрузка...</p>
              ) : (
                <div>
                  <p className="round-text">{roundData?.story || roundData?.message || JSON.stringify(roundData, null, 2) || 'Нет данных хода.'}</p>
                </div>
              )}
            </div>
          </div>
        </section>
      </main>
      <FooterSection />
    </Layout>
  );
}

export default GamePage;
